import{_ as r,c as a,o as t,ah as l}from"./chunks/framework.DNBwxV9x.js";const f=JSON.parse('{"title":"Software","description":"","frontmatter":{},"headers":[],"relativePath":"software.md","filePath":"software.md"}'),o={name:"software.md"};function n(s,e,i,p,h,d){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="software" tabindex="-1">Software <a class="header-anchor" href="#software" aria-label="Permalink to “Software”">​</a></h1><p>Must-have apps for security, productivity, and media.</p><h2 id="essential-apps" tabindex="-1">Essential Apps <a class="header-anchor" href="#essential-apps" aria-label="Permalink to “Essential Apps”">​</a></h2><p><strong>Browsers</strong></p><ul><li><p><a href="https://www.mozilla.org/en-US/firefox/" target="_blank" rel="noreferrer">Firefox</a> - must have <a href="https://addons.mozilla.org/en-US/firefox/addon/ublock-origin/" target="_blank" rel="noreferrer">ublock</a> extension</p></li><li><p><a href="https://brave.com/" target="_blank" rel="noreferrer">Brave</a> - inbuilt adblocker, <a href="https://youtu.be/W6cKFliWW6Q" target="_blank" rel="noreferrer">debloat guide</a></p></li></ul><p><strong>Privacy &amp; Security</strong></p><ul><li><p><a href="https://www.malwarebytes.com/" target="_blank" rel="noreferrer">MalwareBytes</a> - antivirus</p></li><li><p><a href="https://protonvpn.com/" target="_blank" rel="noreferrer">Proton</a> - VPN</p></li></ul><div class="info custom-block"><p class="custom-block-title">One can use package manager(s) like <a href="https://learn.microsoft.com/en-us/windows/package-manager/winget/#install-winget" target="_blank" rel="noreferrer">winget</a>, <a href="https://scoop.sh/" target="_blank" rel="noreferrer">scoop</a>, <a href="https://chocolatey.org/install" target="_blank" rel="noreferrer">chocolatey</a> for updating apps like mpv, 7zip, vlc, hugo, etc</p><p>package managers automate installation, updates, and dependency handling, saving time and effort + they allow bulk installs and easy version control, which manual .exe or .msi downloads can’t.</p><p>if you have to choose one, I would go with scoop, make sure its maintained by genuine source and is updated often.</p></div><p><strong>File Management</strong></p><ul><li><p><a href="https://www.7-zip.org/" target="_blank" rel="noreferrer">7zip</a> - file archiver</p></li><li><p><a href="https://www.advancedrenamer.com/" target="_blank" rel="noreferrer">Advanced Renamer</a>, <a href="https://www.bulkrenameutility.co.uk/" target="_blank" rel="noreferrer">Bulk Renamer</a> - bulk renamer</p></li></ul><p><strong>Media Players</strong></p><ul><li><p><a href="https://scoop.sh/#/apps?q=mpv-git" target="_blank" rel="noreferrer">MPV</a> - media player</p></li><li><p><a href="https://www.videolan.org/vlc/" target="_blank" rel="noreferrer">VLC</a> - media player</p></li></ul><h2 id="optional-utility-apps" tabindex="-1">Optional/Utility Apps <a class="header-anchor" href="#optional-utility-apps" aria-label="Permalink to “Optional/Utility Apps”">​</a></h2><ul><li><p><a href="https://github.com/KenneyNL/Adobe-Alternatives" target="_blank" rel="noreferrer">Adobe Alternatives</a> - list of alternatives for Adobe software</p></li><li><p><a href="https://flameshot.org/#download" target="_blank" rel="noreferrer">Flameshot</a> - better screenshot tool</p></li><li><p><a href="https://github.com/yt-dlp/yt-dlp" target="_blank" rel="noreferrer">YTdlp</a> - <a href="https://www.reddit.com/r/youtubedl/comments/tt0cqk/comment/i2usxtj/?utm_source=share&amp;utm_medium=web3x&amp;utm_name=web3xcss&amp;utm_term=1&amp;utm_content=share_button" target="_blank" rel="noreferrer">installation guide</a> - audio/video downloader</p></li><li><p><a href="https://getsharex.com/downloads" target="_blank" rel="noreferrer">ShareX</a> - screenshot tool with extensive features</p></li><li><p><a href="https://www.bleachbit.org/download/windows" target="_blank" rel="noreferrer">Bleachbit</a> - clean your system and disk space</p></li><li><p><a href="https://www.revouninstaller.com/revo-uninstaller-free-download/" target="_blank" rel="noreferrer">Revo Uninstaller</a> - completely uninstall programs and registry</p></li><li><p><a href="https://abdownloadmanager.com/" target="_blank" rel="noreferrer">AB Download Manager</a> - download manager for speeding up download(s)</p></li><li><p><a href="https://jdownloader.org/" target="_blank" rel="noreferrer">Jdownloader</a> - another download manager, suitable for batch downloads</p></li><li><p><a href="https://localsend.org/" target="_blank" rel="noreferrer">Local Send</a> - file sharing to nearby devices</p></li><li><p><a href="https://notepad-plus-plus.org/downloads/" target="_blank" rel="noreferrer">Notepad++</a> - better notepad</p></li><li><p><a href="https://github.com/Vencord/Vesktop" target="_blank" rel="noreferrer">Vesktop</a> - modified discord client</p></li><li><p><strong>Downloaders &amp; Torrents</strong></p><ul><li><p><a href="https://www.qbittorrent.org/" target="_blank" rel="noreferrer">Qbittorrent</a> - best torrent client</p></li><li><p><a href="https://nyaa.si/" target="_blank" rel="noreferrer">Nyaa</a> - Anime torrents</p></li></ul></li></ul><h2 id="cracks" tabindex="-1">Cracks <a class="header-anchor" href="#cracks" aria-label="Permalink to “Cracks”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Turn off antivirus before installation of Cracks software or Game Repacks</p><p>It&#39;s recommended to turn it off because it may flag the crack and just delete it. Imagine waiting an hour or more for it to install, and having the antivirus delete the crack making the game unplayable.</p></div><ul><li><p><a href="https://cracksurl.com/" target="_blank" rel="noreferrer">Cracksurl</a>, <a href="https://lrepacks.net/" target="_blank" rel="noreferrer">Lrepacks</a> - general software</p></li><li><p><a href="https://w16.monkrus.ws/" target="_blank" rel="noreferrer">Monkrus</a>, <a href="https://vk.com/monkrus" target="_blank" rel="noreferrer">2</a>, <a href="https://monkrus.dvuzu.com/" target="_blank" rel="noreferrer">3</a> - adobe products</p></li><li><p><a href="https://rutracker.org/" target="_blank" rel="noreferrer">Rutracker</a> - extensive software</p></li></ul>',17)])])}const u=r(o,[["render",n]]);export{f as __pageData,u as default};
